onSubmit:
{{
  (function() {
    if (!inp_search_serial.text) return;

    qry_search_by_serial.run(
      function() {
        if (qry_search_by_serial.data.length > 0) {
          navigateTo(
            'AssetView',
            { assetId: qry_search_by_serial.data[0].asset_id },
            'SAME_WINDOW'
          );
        } else {
          showAlert(
            'No asset found for serial "' + inp_search_serial.text + '"',
            'warning'
          );
          resetWidget('inp_search_serial');
        }
      },
      function() {
        showAlert('Search failed — try again', 'error');
      }
    );
  })()
}}
